import React, { useEffect, useState } from "react";
import { Bar, Pie } from "react-chartjs-2";
import {
  Chart as ChartJS,
  Title,
  Tooltip,
  Legend,
  BarElement,
  ArcElement,
  CategoryScale,
  LinearScale,
} from "chart.js";

ChartJS.register(
  Title,
  Tooltip,
  Legend,
  BarElement,
  ArcElement,
  CategoryScale,
  LinearScale
);

function AdminDashboard() {
  const [data, setData] = useState({
    ventasMes: 0,
    pedidosPendientes: 0,
    stockBajo: 0,
    clientesActivos: 0,
  });

  useEffect(() => {
    fetch("http://localhost:3001/admin/dashboard")
      .then((res) => res.json())
      .then((json) => setData(json))
      .catch((err) => console.error("Error al cargar dashboard:", err));
  }, []);

  // Datos de ejemplo para gráficos
  const ventasData = {
    labels: ["Ene", "Feb", "Mar", "Abr", "May"],
    datasets: [
      {
        label: "Ventas Mensuales",
        data: [2000, 4000, 6000, 8000, 10000],
        backgroundColor: "#4CAF50",
      },
    ],
  };

  const productosData = {
    labels: ["Laptop Pro", "Smartphone X", "Auriculares Z"],
    datasets: [
      {
        data: [40, 35, 25],
        backgroundColor: ["#2196F3", "#FF9800", "#F44336"],
      },
    ],
  };

  return (
    <div style={{ padding: "20px", fontFamily: "Arial, sans-serif" }}>
      <h2>Panel de Administración</h2>

      {/* Tarjetas de métricas */}
      <div style={{ display: "flex", gap: "20px", flexWrap: "wrap" }}>
        <Card title="Ventas del Mes" value={`$${data.ventasMes}`} color="#4CAF50" />
        <Card title="Pedidos Pendientes" value={data.pedidosPendientes} color="#FF9800" />
        <Card title="Stock Bajo" value={data.stockBajo} color="#F44336" />
        <Card title="Clientes Activos" value={data.clientesActivos} color="#2196F3" />
      </div>

      {/* Gráfico de barras */}
      <div style={{ marginTop: "40px" }}>
        <h3>Ventas Mensuales</h3>
        <Bar data={ventasData} />
      </div>

      {/* Gráfico circular */}
      <div style={{ marginTop: "40px", maxWidth: "400px" }}>
        <h3>Productos Más Vendidos</h3>
        <Pie data={productosData} />
      </div>

      {/* Tabla de usuarios recientes */}
      <div style={{ marginTop: "40px" }}>
        <h3>Usuarios Recientes</h3>
        <table style={{ width: "100%", borderCollapse: "collapse" }}>
          <thead>
            <tr style={{ background: "#f0f0f0" }}>
              <th style={{ border: "1px solid #ccc", padding: "8px" }}>ID</th>
              <th style={{ border: "1px solid #ccc", padding: "8px" }}>Nombre</th>
              <th style={{ border: "1px solid #ccc", padding: "8px" }}>Email</th>
              <th style={{ border: "1px solid #ccc", padding: "8px" }}>Rol</th>
            </tr>
          </thead>
          <tbody>
            <tr>
              <td style={{ border: "1px solid #ccc", padding: "8px" }}>1</td>
              <td style={{ border: "1px solid #ccc", padding: "8px" }}>Carlos Pérez</td>
              <td style={{ border: "1px solid #ccc", padding: "8px" }}>carlos.perez@email.com</td>
              <td style={{ border: "1px solid #ccc", padding: "8px" }}>Cliente</td>
            </tr>
            <tr>
              <td style={{ border: "1px solid #ccc", padding: "8px" }}>2</td>
              <td style={{ border: "1px solid #ccc", padding: "8px" }}>Marta López</td>
              <td style={{ border: "1px solid #ccc", padding: "8px" }}>marta.lopez@email.com</td>
              <td style={{ border: "1px solid #ccc", padding: "8px" }}>Vendedor</td>
            </tr>
            <tr>
              <td style={{ border: "1px solid #ccc", padding: "8px" }}>3</td>
              <td style={{ border: "1px solid #ccc", padding: "8px" }}>Juan Gómez</td>
              <td style={{ border: "1px solid #ccc", padding: "8px" }}>juan.gomez@email.com</td>
              <td style={{ border: "1px solid #ccc", padding: "8px" }}>Admin</td>
            </tr>
          </tbody>
        </table>
      </div>
    </div>
  );
}

function Card({ title, value, color }) {
  return (
    <div
      style={{
        flex: "1 1 200px",
        background: color,
        color: "white",
        padding: "20px",
        borderRadius: "8px",
        textAlign: "center",
        boxShadow: "0 4px 6px rgba(0,0,0,0.1)",
      }}
    >
      <h3>{title}</h3>
      <p style={{ fontSize: "24px", fontWeight: "bold" }}>{value}</p>
    </div>
  );
}

export default AdminDashboard;
